import { Component, signal } from '@angular/core';
import { CommonModule, PercentPipe } from '@angular/common';
import { BIOMES, BiomeType } from '../../utils/interfaces/biomes';
import { PLANTS, Plant } from '../../utils/interfaces/plants';
import { getTool } from '../../utils/interfaces/tools';
import { ResourceType, getResource } from '../../utils/interfaces/resource';
import { FoodType, getFood } from '../../utils/interfaces/food';
import { ButtonComponent } from '../../components/dump/button/button';
import { HeaderComponent } from '../../components/dump/header/header';
import { RouterLink } from '@angular/router';

interface PlantInBiome extends Plant {
  id: string;
  spawnProbability: number;
}

@Component({
  selector: 'wiki-page',
  imports: [CommonModule, PercentPipe, ButtonComponent, HeaderComponent, RouterLink],
  standalone: true,
  templateUrl: './wiki.html',
})
export class WikiPage {
  private readonly biomeNames: Record<BiomeType, string> = {
    [BiomeType.sea]: 'Morze',
    [BiomeType.inlandWaters]: 'Wody śródlądowe',
    [BiomeType.waterfront]: 'Wybrzeże',
    [BiomeType.grass]: 'Łąka',
    [BiomeType.forest]: 'Las',
    [BiomeType.mountain]: 'Skały',
    [BiomeType.snow]: 'Śnieg',
  };

  protected readonly getTool = getTool;

  protected readonly wikiData = signal(
    Object.entries(BIOMES).map(([key, biomeData]) => {
      const biomeType = key as BiomeType;
      const plantsInThisBiome: PlantInBiome[] = Object.entries(PLANTS)
        .filter(([, plant]) => Array.isArray(plant.locations) && plant.locations.some((loc) => loc.location === biomeType))
        .map(([plantId, plant]) => ({
          ...plant,
          id: plantId,
          spawnProbability: (Array.isArray(plant.locations) ? plant.locations.find((loc) => loc.location === biomeType)?.probability : 0) ?? 0,
        }));

      return {
        type: biomeType,
        name: this.biomeNames[biomeType] ?? biomeType,
        ...biomeData,
        plants: plantsInThisBiome,
      };
    }),
  );

  protected getLootLabel(type: FoodType | ResourceType): string {
    const food = getFood(type as FoodType);
    if (food) {
      return food.name;
    }
    const resource = getResource(type as ResourceType);
    if (resource) {
      return resource.name;
    }
    return type;
  }
}
